    public function importData() {
        $data = $this->_batchImport;
        $institute_code = $this->session->userdata("institute_code");
		date_default_timezone_set('Asia/Kolkata');
		$date = date('Y-m-d', now());
		$logged_user = $this->session->userdata('user_name');
        
        for($i=0;$i<sizeof($data);$i++)
		{
			$appl_no = '';
			
			
			//$txtName = $data[$i]['applicant_name'];
			//$appl_no = $data[$i]['appl_no'];
			//$txtRollNo = $data[$i]['applicant_id'];
			//$cmbResult = $data[$i]['field'];
			$header_1 = $data[$i]['header_1'];
			$header_2 	= $data[$i]['header_2'];
			$txtRollNo = $data[$i]['applicant_id'];
			$program_code = $data[$i]['program_code'];
            $barcode = $data[$i]['barcode'];
            $series = $data[$i]['series'];
            $lang = $data[$i]['lang'];
            $answer = $data[$i]['answer'];
            $total_mark=$data[$i]['total_mark'];
			$round_data = $data[$i]['round_data'];
			
			$this->db->select("D.full_name,D.category,omr_no,B.applied_program,B.appl_no");
			$this->db->from('admitcard_published B');
			$this->db->join('applicant_appl_overview C','B.appl_no = C.appl_no','left');
			$this->db->join('applicant_master D','C.reg_user_id = D.reg_user_id AND C.applied_program = D.applied_program','left');
			$this->db->where("B.omr_no",$txtRollNo);
			$this->db->where("B.applied_program",$program_code);
			$result = $this->db->get();
			$output_data = $result->result_array();
			$txtCategory = '';
			foreach($output_data as $row)
			{
				$txtName = $row['full_name'];
				$txtRollNo = $row['omr_no'];
				$appl_no = $row['appl_no'];
				$txtCategory = $row['category'];
				$program_code = $row['applied_program'];
			}
			if($total_mark != '')
			{
				$this->db->where("program_code",$program_code);
				$this->db->where("applicant_id",$txtRollNo);
				$this->db->where("round_no",$round_data);
				$this->db->select("count(program_code) as program_code");
				$this->db->from("applicant_exam_result");
				
				$result = $this->db->get();
				$output_data = $result->result_array();
				foreach($output_data as $row)
				{
					$cnt = $row['program_code'];
				}
				$cutoff_mark = '0';
				$this->db->where("program_code",$program_code);
				$this->db->where("category_code",$txtCategory);
				$this->db->select("cutoff_mark");
				$this->db->from("category_cutoff_details");
				
				$result = $this->db->get();//echo $this->db->last_query(); die();
				$output_data = $result->result_array();
				foreach($output_data as $row)
				{
					$cutoff_mark = $row['cutoff_mark'];
				}
				$cmbResult = 'Selected';
				if($total_mark >= $cutoff_mark)
				{
					$cmbResult = 'Selected';
				}
				else
				{
					$cmbResult = 'Not Selected';
				}
				
				if($cnt == '0')
				{
					$new_array = array( 
						"program_code"  	=>$program_code,
						"applicant_id"  	=>$txtRollNo,
						"applicant_name"  	=>$txtName,
						'header_1' 			=>$header_1, 
						'header_2' 			=> $header_2,
						'applicant_id' 		=> $txtRollNo,
                		'barcode' 			=> $barcode,
                		'series' 			=> $series,
                		'lang' 				=> $lang,
                		'answer' 			=> $answer,
                		'total_mark'		=>$total_mark,
                		'result'			=>$cmbResult,
						"round_no"  		=>$round_data,
						"created_by" 		=>$logged_user,
						"created_on" 		=>$date
					);
					$sql = $this->db->insert('applicant_exam_result',$new_array);
					if(!$sql){
						$dbStatus = "ERROR";
						$dbMessage = "Error Inserting";
					}
				}
				else
				{
					$new_array = array( 
						"applicant_name"  	=>$txtName,
						'header_1' 			=>$header_1, 
						'header_2' 			=> $header_2,
						'applicant_id' 		=> $txtRollNo,
                		'barcode' 			=> $barcode,
                		'series' 			=> $series,
                		'lang' 				=> $lang,
                		'answer' 			=> $answer,
                		'total_mark'		=>$total_mark,
                		'result'			=>$cmbResult,
						"round_no"  		=>$round_data,
						"created_by" 		=>$logged_user,
						"created_on" 		=>$date
					);
					$this->db->where("program_code",$program_code);
					$this->db->where("applicant_id",$txtRollNo);
					$this->db->where("round_no",$round_data);
					$sql = $this->db->update('applicant_exam_result',$new_array);
					if(!$sql){
						$dbStatus = "ERROR";
						$dbMessage = "Error Inserting";
					}
				}
			}
			$new_array = array( 
				"user_id"  			=>$logged_user,
