    public function split_string($string,$needle,$nth){
		$max = strlen($string);
		$n = 0;
		for($i=0;$i<$max;$i++){
		    if($string[$i]==$needle){
		        $n++;
		        if($n>=$nth){
		            break;
		        }
		    }
		}
		$arr[] = substr($string,0,$i);
		$arr[] = substr($string,$i+1,$max);

		return $arr;
	}	
	public function convertBirthdateToText($date){
		 global $ones, $oneswords, $tens, $triplets;
		 $ones = array('','One','Two','Three','Four','Five','Six','Seven','Eight','Nine','Ten','Eleven','Twelve','Thirteen','Fourteen','Fifteen','Sixteen','Seventeen','Eighteen','Nineteen','Twenty','Twenty-one','Twenty-two','Twenty-three','Twenty-four','Twenty-five','Twenty-six','Twenty-seven','Twenty-eight','Twenty-nine','Thirty','Thirty-one','Thirty-two','Thirty-three','Thirty-four','Thirty-five','Thirty-six','Thirty-seven','Thirty-eight','Thirty-nine','Fourty',
	      'Fourty-one','Fourty-two','Fourty-three','Fourty-four','Fourty-five','Fourty-six','Fourty-seven','Fourty-eight','Fourty-nine','Fifty','Fifty-one','Fifty-two','Fifty-three','Fifty-four','Fifty-five','Fifty-six','Fifty-seven','Fifty-eight','Fifty-nine','Sixty','Sixty-one','Sixty-two','Sixty-three','Sixty-four','Sixty-five','Sixty-six','Sixty-seven','Sixty-eight','Sixty-nine','Seventy',
	      'Seventy-one','Seventy-two','Seventy-three','Seventy-four','Seventy-five','Seventy-six','Seventy-seven','Seventy-eight','Seventy-nine','Eighty','Eighty-one','Eighty-two','Eighty-three','Eighty-four','Eighty-five','Eighty-six','Eighty-seven','Eighty-eight','Eighty-nine','Ninety','Ninety-one','Ninety-two','Ninety-three','Ninety-four','Ninety-five','Ninety-six','Ninety-seven','Ninety-eight','Ninety-nine');
	    
		$oneswords = array(
			"",
			 " first",
			 " second",
			 " third",
			 " fourth",
			 " fiveth",
			 " sixth",
			 " seventh",
			 " eighth",
			 " nineth",
			 " tenth",
			 " eleventh",
			 " twelveth",
			 " thirteenth",
			 " fourteenth",
			 " fifteenth",
			 " sixteenth",
			 " seventeenth",
			 " eighteenth",
			 " nineteenth",
			 "twentiethth",
			 "thirtieth"
		);
		 
		$tens = array(
			 "",
			 "",
			 " twenty",
			 " thirty",
			 " forty",
			 " fifty",
			 " sixty",
			 " seventy",
			 " eighty",
			 " ninety"
		);
	    list( $day,$month,$year) = explode('-', $date);
	    /*echo $date;
	    die();*/
	   	" Day: $day; Month: $month; Year: $year<br />\n";
		$str = "";
		$year1 ="";
		$year2 = "";
		//CONVERT DAY INTO WORDS
		if($day < '10'){
			$day = ltrim($day, "0");
		}
		if($day == '20'){
			 $str =  'Twentieth of ';
		}
		elseif($day == '30'){
			 $str =  'Thirtieth of ';
		}
		elseif($day < '20'){
			 $str = ucwords($oneswords[$day]);
		}
		elseif($day > '20' && $day < '30' ){
			$str .= 'Twenty' . ucwords($oneswords[$day % 10]).' of ';
		}
		elseif($day > '30'){
			 $str .= 'Thirty' . ucwords($oneswords[$day % 10]).' of ';
		}
		/*echo $str;
		die();*/
		//CONVERT MONTH INTO WORDS
		 $monthName = date('F', mktime(0, 0, 0, $month, 10));
		 $str .=  " " .$monthName." ";
		 //CONVERT YEAR INTO WORDS
		$year1 = substr($year,0,2);
		$year2 = ltrim(substr($year,2,4), '0');
		
		if($year2 != '')
		{
			$year_second = substr($year,1,1);
			
			if($year_second == 0)
			{
				$y = substr($year,0,1);
				$str .= ucwords($ones[substr($year,0,1)]).' Thousand '.ucwords($ones[$year2]);
				
			}
			else
			{
				$str .= ucwords($ones[$year1]).' Hundred '.ucwords($ones[$year2]);
			}
			return $str;
		}
		else
		{
			$str .= ucwords($ones[$year1]).' Hundred ';
			return $str;
		}
		 //$str .= $ones[$year1].' Hundred '.$ones[$year2];
		  
		
	}

	// OMR data excel reports
    
	public function excel_consolidated_report($data)
	{
		$program = $data['program'];
		
		$result = $this->db->query("SELECT full_name,A.roll_no,total_marks,@row_number:=@row_number+1 AS rank
						FROM sheet_table_history A
						INNER JOIN admitcard_published B ON A.roll_no = B.omr_no
						LEFT JOIN applicant_appl_overview C ON B.appl_no = C.appl_no AND B.applied_program = C.applied_program
						LEFT JOIN applicant_master D ON C.reg_user_id = D.reg_user_id AND C.applied_program = D.applied_program
						JOIN (SELECT @row_number:=0) AS t
						WHERE B.applied_program = '$program'
						ORDER BY A.roll_no");
		return $result->result();
	}
	public function excel_subject_wise_header_report($data)
	{
		$program = $data['program'];
		$result = $this->db->query("SELECT subject_names FROM sheet_table_history A 
					INNER JOIN admitcard_published B ON A.roll_no = B.omr_no
					WHERE B.applied_program = '$program'
					LIMIT 1");
		return $result->result();
	}
	public function excel_subject_wise_report($data)
	{
		$program = $data['program'];
		$result = $this->db->query("SELECT full_name,A.roll_no,subject_total_marks,total_marks,@row_number:=@row_number+1 AS rank
				FROM sheet_table_history A
				INNER JOIN admitcard_published B ON A.roll_no = B.omr_no
				LEFT JOIN applicant_appl_overview C ON B.appl_no = C.appl_no AND B.applied_program = C.applied_program
				LEFT JOIN applicant_master D ON C.reg_user_id = D.reg_user_id AND C.applied_program = D.applied_program
				JOIN (SELECT @row_number:=0) AS t
				WHERE B.applied_program = '$program'
				ORDER BY A.roll_no");
		return $result->result();
	}
	public function excel_consolidated_count_report($data)
	{
		$program = $data['program'];
		$result = $this->db->query("SELECT full_name,A.roll_no,right_count,wrong_count,blank_count,total_marks,@row_number:=@row_number+1 AS rank
						FROM sheet_table_history A
						INNER JOIN admitcard_published B ON A.roll_no = B.omr_no
						LEFT JOIN applicant_appl_overview C ON B.appl_no = C.appl_no AND B.applied_program = C.applied_program
						LEFT JOIN applicant_master D ON C.reg_user_id = D.reg_user_id AND C.applied_program = D.applied_program
						JOIN (SELECT @row_number:=0) AS t
						WHERE B.applied_program = '$program'
						ORDER BY A.roll_no");
		return $result->result();
	}
	public function excel_subject_wise_count_report($data)
	{
		$program = $data['program'];
		$result = $this->db->query("SELECT full_name,A.roll_no,subject_names,subject_right_count,subject_wrong_count,subject_blank_count,subject_total_marks,total_marks,@row_number:=@row_number+1 AS rank
						FROM sheet_table_history A
						INNER JOIN admitcard_published B ON A.roll_no = B.omr_no
						LEFT JOIN applicant_appl_overview C ON B.appl_no = C.appl_no AND B.applied_program = C.applied_program
						LEFT JOIN applicant_master D ON C.reg_user_id = D.reg_user_id AND C.applied_program = D.applied_program
						JOIN (SELECT @row_number:=0) AS t
						WHERE B.applied_program = '$program'
						ORDER BY A.roll_no"); 
		return $result->result();
	}
	
	public function scrutiny_program_details($data)
	{
		$sel_program_code = $data['program_code'];
		$this->db->select("A.program_group,A.program_name,advt_no,DATE_FORMAT(A.advt_date,'%d-%m-%Y') AS advt_date");
		$this->db->from('program_master A');
		$this->db->where('A.program_code',$sel_program_code);
		$query = $this->db->get();
		return $query->result_array();
	}
	
	public function excel_synopsis_report($data)
	{
		$sel_program_code = $data['program_code'];
		$sel_pro_ins_code = explode('_',$sel_program_code);
		$ins_code = $sel_pro_ins_code[1];
		$sel_pro_code = 'PROG_'.$sel_pro_ins_code[1];
		
		
		$this->db->select("B.appl_no,A.full_name,A.father_name,
							CONCAT(C.address_1,' , ',C.post_office,' , ', C.city_name,' , ', D.state_name,' , ', E.district_name,' - ', C.pin) AS address,
							A.reg_user_id AS mobile_no,F.email_id,G.category_name,DATE_FORMAT(A.dob,'%d-%m-%Y') AS dob,A.age,
							GROUP_CONCAT(DISTINCT CONCAT(qual_desc_1, ' in ', year_of_passing, '\n') ORDER BY H.id SEPARATOR '') AS qual,
							GROUP_CONCAT(DISTINCT CONCAT(SUBSTRING_INDEX(I.duration, '/', 1),' years and ',SUBSTRING_INDEX(I.duration, '/', -1),' months in ', I.organization, ' as ', I.post_held, '\n') ORDER BY I.id SEPARATOR '') AS experience,
							J.money_receipt_no AS dd_no,DATE_FORMAT(J.depositdate,'%d-%m-%Y') AS depositdate,amount,A.scrutiny_remark");
		$this->db->from('applicant_master A');
		$this->db->join('applicant_appl_overview B','A.reg_user_id = B.reg_user_id AND A.applied_program = B.applied_program','INNER');
		$this->db->join('applicant_address C','A.comm_address_ref_id = C.address_ref_id','INNER');
		$this->db->join('state_master D','C.state_code = D.state_code','INNER');
		$this->db->join('district_master E','C.district_code = E.district_code','INNER');
		$this->db->join('applicant_reg_master F',"A.reg_user_id = F.reg_user_id AND F.applied_program = '$sel_pro_code'",'INNER');
		$this->db->join('category_master G','A.category = G.category_code','INNER');
		$this->db->join('applicant_qualification_detail H','A.reg_user_id = H.reg_user_id AND A.applied_program = H.applied_program','INNER');
		$this->db->join('applicant_work_experience_detail I','A.reg_user_id = I.reg_user_id AND A.applied_program = I.applied_program','INNER');
		$this->db->join('applicant_form_fee_overview J','B.appl_no = J.appl_no','INNER');
		$this->db->where('B.appl_status','Verified');
		$this->db->where('A.applied_program',$sel_program_code);
		$this->db->group_by('B.appl_no,F.email_id');
			
		$query = $this->db->get();
		/*echo $this->db->last_query();
		die();*/
		return $query->result_array();
	}

